sys_script_client.script:
function onChange(control, oldValue, newValue, isLoading, isTemplate) {
    if (isLoading || newValue == '') {
        return;
    }

    g_form.clearMessages();

    if (newValue == 'MacBook') {
        g_form.addInfoMessage('MacBook setup task will be created automatically after submission.');
    } else if (newValue == 'Windows') {
        g_form.addInfoMessage('Windows device configuration tasks will be generated automatically.');
    } else if (newValue == 'Linux') {
        g_form.addInfoMessage('Linux workstation setup requires additional configuration tasks.');
    }
}
